#include<bits/stdc++.h>
using namespace std;
const int NM = 1e5+5;
struct node{long long h,id,pst,nxt;}a[NM];
long long n,m,st[NM],mk[NM];
long long pos[NM],xa[NM],xb[NM];
long long dp[25][NM][2],fa[25][NM][2],fb[25][NM][2];
long long ans_a,ans_b,ans_id;
long long read(){
    long long su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void write(long long num){
    if(num>9)write(num/10);
    putchar(num%10+'0');
}
bool cmp(node d1,node d2){return d1.h<d2.h;}
int main(){
    n=read();
    for(int i=1;i<=n;i++)a[i].h=read(),a[i].id=i;
    mk[0]=read();m=read();
    for(int i=1;i<=m;i++)st[i]=read(),mk[i]=read();
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)pos[a[i].id]=i;
    for(int i=1;i<=n;i++)a[i].pst=i-1,a[i].nxt=i+1;
    a[1].pst=0,a[n].nxt=0;
    for(int o=1;o<=n;o++){
        int i=pos[o];
        int p1=a[i].pst,p2=a[i].nxt,q1,q2;
        if(!p2)xb[o]=a[p1].id,q1=a[p1].pst,q2=p2;
        else if(!p1)xb[o]=a[p2].id,q1=p1,q2=a[p2].nxt;
        else if(abs(a[p1].h-a[i].h)<abs(a[p2].h-a[i].h)||(abs(a[p1].h-a[i].h)==abs(a[p2].h-a[i].h)&&a[p1].h<a[p2].h))
            xb[o]=a[p1].id,q1=a[p1].pst,q2=p2;
        else xb[o]=a[p2].id,q1=p1,q2=a[p2].nxt;
        if(!q2)xa[o]=a[q1].id;
        else if(!q1)xa[o]=a[q2].id;
        else if(abs(a[q1].h-a[i].h)<abs(a[q2].h-a[i].h)||(abs(a[q1].h-a[i].h)==abs(a[q2].h-a[i].h)&&a[q1].h<a[q2].h))xa[o]=a[q1].id;
        else xa[o]=a[q2].id;
        node tmp=a[i];
        a[tmp.pst].nxt=tmp.nxt;
        a[tmp.nxt].pst=tmp.pst;
        a[i].pst=0,a[i].nxt=0;
        pos[a[tmp.pst].id]=tmp.pst;
        pos[a[tmp.nxt].id]=tmp.nxt;
    }
    for(int i=1;i<=n;i++){
        if(xa[i]){
            dp[0][i][0]=xa[i];
            fa[0][i][0]=abs(a[pos[i]].h-a[pos[xa[i]]].h);
            fb[0][i][0]=0;
        }
        if(xb[i]){
            dp[0][i][1]=xb[i];
            fa[0][i][1]=0;
            fb[0][i][1]=abs(a[pos[i]].h-a[pos[xb[i]]].h);
        }
    }
    for(int i=1;i<=20;i++)
        for(int j=1;j+(1<<i)-1<=n;j++)
            for(int k=0;k<=1;k++){
                int xt=(i==1?k^1:k);
                if(dp[i-1][j][k])dp[i][j][k]=dp[i-1][dp[i-1][j][k]][xt];
                if(dp[i][j][k]){
                    fa[i][j][k]=fa[i-1][j][k]+fa[i-1][dp[i-1][j][k]][xt];
                    fb[i][j][k]=fb[i-1][j][k]+fb[i-1][dp[i-1][j][k]][xt];
                }
            }
    ans_a=0x3f3f3f3f,ans_b=0,ans_id=0;
    for(int i=1;i<=n;i++){
        long long len_a=0,len_b=0;
        long long now=i,k=0,hav=mk[0];
        for(int j=20;j>=0;j--)
            if(dp[j][now][k]&&fa[j][now][k]+fb[j][now][k]<=hav){
                hav-=fa[j][now][k]+fb[j][now][k];
                len_a+=fa[j][now][k],len_b+=fb[j][now][k];
                now=dp[j][now][k];
            }
        if(len_a+len_b==0)continue;
        else if(len_b==0&&(!ans_id||(a[pos[i]].h>a[pos[ans_id]].h&&ans_b==0)))ans_id=i;
        else if(len_a*ans_b<len_b*ans_a||(len_a*ans_b==len_b*ans_a&&a[pos[i]].h>a[pos[ans_id]].h))
            ans_a=len_a,ans_b=len_b,ans_id=i; else;
    }
    write(ans_id);cout<<"\n";
    for(int i=1;i<=m;i++){
        long long len_a=0,len_b=0;
        long long now=st[i],k=0,hav=mk[i];
        for(int j=20;j>=0;j--)
            if(dp[j][now][k]&&fa[j][now][k]+fb[j][now][k]<=hav){
                hav-=fa[j][now][k]+fb[j][now][k];
                len_a+=fa[j][now][k],len_b+=fb[j][now][k];
                now=dp[j][now][k];
            }
        cout<<len_a<<" "<<len_b<<"\n";
    }
    return 0;
}
